import{_ as a,o as i,c as t,a2 as s}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"PRD-004 — Mission Library","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-004.md","filePath":"prd/PRD-004.md"}'),o={name:"prd/PRD-004.md"};function r(n,e,l,h,c,d){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="prd-004-—-mission-library" tabindex="-1">PRD-004 — Mission Library <a class="header-anchor" href="#prd-004-—-mission-library" aria-label="Permalink to &quot;PRD-004 — Mission Library&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Sources · 02_Project_Concept.md §mission-library · 03_Data_Catalog.md Audiences · curious learner, STEM student, contributor (PA §audiences) Promises · real mission data fully attributed, educational at every level (PA §promises) Principles · attribution is design, data over code (PA §principles) Why this is a PRD · The library is where 60 years of spaceflight become navigable. It changes what a person knows about what humanity has done in space — not just the famous missions, but the failures, the firsts, and the capability ladder that makes the next mission possible.</p></blockquote><p>A teacher is preparing a lesson on the Moon-to-Mars capability ladder. They filter to Moon missions, sort chronologically, and click Luna 9. The panel opens. &quot;First spacecraft to achieve a soft landing on another world.&quot; They click Lunokhod 1. &quot;First remote-controlled rover.&quot; They click Chandrayaan-3. &quot;First soft landing near the lunar south pole, where water ice deposits make Artemis III&#39;s target scientifically significant.&quot; The lesson writes itself.</p><h2 id="the-problem" tabindex="-1">The problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The problem&quot;">​</a></h2><p>Most people&#39;s knowledge of space exploration is three missions deep: Apollo 11, Curiosity, and whatever launched last year. The 28 missions that shaped the capability to reach Mars — and the 14 that proved every technique required along the way — are invisible.</p><h2 id="the-experience" tabindex="-1">The experience <a class="header-anchor" href="#the-experience" aria-label="Permalink to &quot;The experience&quot;">​</a></h2><p>The library opens on a card grid of all 28 missions. Each card shows agency colour, mission name, type, year, and a one-line &quot;first.&quot; The filter bar at the top has DESTINATION (all, Mars, Moon) and STATUS (all, active, flown, planned) filters.</p><p>The user clicks a card. The detail panel slides in with the full mission record: agency, launch and arrival dates, transit time, launch vehicle, payload mass, delta-v budget. The editorial description in Crimson Pro italic tells the story of the mission. The GALLERY tab shows mission imagery from the NASA Images API. The LEARN tab has tiered links — Wikipedia for quick reference, NASA mission page for depth, peer-reviewed papers for the STEM student.</p><p>The user clicks &quot;FLY THIS MISSION.&quot; They are taken to <code>/fly?mission=curiosity</code>. The fly screen loads Curiosity&#39;s 253-day transit. They see the transfer arc. The 259-day cruise is no longer abstract.</p><h2 id="why-now" tabindex="-1">Why now <a class="header-anchor" href="#why-now" aria-label="Permalink to &quot;Why now&quot;">​</a></h2><p>The library is the archive — it doesn&#39;t require the other screens but it enriches them. Every mission in the library is flyable via the fly screen. The library is also the entry point for contributors: adding a mission means adding a JSON file and testing that it shows correctly in the library.</p><h2 id="success-looks-like" tabindex="-1">Success looks like <a class="header-anchor" href="#success-looks-like" aria-label="Permalink to &quot;Success looks like&quot;">​</a></h2><p>A user who thought they knew space exploration discovers three missions they&#39;d never heard of and can explain their significance.</p><p>The Moon capability ladder — Luna 9 → Lunokhod 1 → Luna 24 → Chandrayaan-3 — is navigable in a single filter session, and a user can articulate why each mission mattered for what came after.</p><p>A contributor adds a new mission by creating a JSON file and testing it in the library without reading any JavaScript.</p><h2 id="out-of-scope" tabindex="-1">Out of scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of scope&quot;">​</a></h2><ul><li>Sorting options beyond chronological (by agency, by delta-v, by outcome)</li><li>User notes or annotations on missions</li><li>Comparing two missions side-by-side</li><li>Missions outside the Mars and Moon destinations (v1 scope)</li></ul><h2 id="the-sharpest-threat" tabindex="-1">The sharpest threat <a class="header-anchor" href="#the-sharpest-threat" aria-label="Permalink to &quot;The sharpest threat&quot;">​</a></h2><p>The one-line &quot;first&quot; is what makes each card worth clicking. If the &quot;first&quot; is generic (&quot;first Mars orbiter&quot;) the card is a list item. If it&#39;s specific and surprising (&quot;first spacecraft to image the far side of Mars at global scale&quot;) the card earns a click. The library&#39;s value lives in the quality of that one line per mission.</p><h2 id="open-threads" tabindex="-1">Open threads <a class="header-anchor" href="#open-threads" aria-label="Permalink to &quot;Open threads&quot;">​</a></h2><ul><li>UXS-004 for full visual contract</li><li>RFC-002 for mission JSON schema</li><li>RFC-004 for <code>?dest=MARS</code> URL param</li></ul><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li>Prototype: <code>docs/prototypes/P04_mission-library.html</code></li><li>Concept: <code>docs/concept/02_Project_Concept.md §mission-library</code></li></ul>',23)])])}const m=a(o,[["render",r]]);export{u as __pageData,m as default};
